import { Component, OnInit, OnDestroy, inject, ChangeDetectionStrategy, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { TaskService } from '../../services/task.service';
import { Task, TaskStatus, TaskPriority } from '../../models/task.model';
import { NavbarComponent } from '../navbar/navbar.component';
import { Subject, debounceTime, distinctUntilChanged, map } from 'rxjs';
import { takeUntil } from 'rxjs/operators';

@Component({
  selector: 'app-task-list',
  standalone: true,
  imports: [CommonModule, FormsModule, NavbarComponent],
  templateUrl: './task-list.component.html',
  styleUrls: ['./task-list.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class TaskListComponent implements OnInit, OnDestroy {
  private taskService = inject(TaskService);
  private router = inject(Router);
  private cdr = inject(ChangeDetectorRef);
  private destroy$ = new Subject<void>();
  private searchTerm$ = new Subject<string>();
  private normalizedSearchTerm = '';
  private searchIndex = new Map<string, string>();

  tasks: Task[] = [];
  filteredTasks: Task[] = [];
  loading = false;
  error = '';
  searchTerm = '';
  selectedFilter: 'all' | 'pending' | 'inProgress' | 'completed' | 'starred' = 'all';
  selectedTaskId: string | null = null;
  deleteConfirmId: string | null = null;
  deleteConfirmTaskTitle = '';
  deleteLoading = false;

  // Status and priority enums for template
  TaskStatus = TaskStatus;
  TaskPriority = TaskPriority;

  ngOnInit(): void {
    // Subscribe to service tasks for real-time updates
    this.taskService.tasks$
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (tasks) => {
          this.setTasks(tasks || []);
          this.applyFilters();
          this.cdr.markForCheck();
        }
      });

    // Handle search with debounce
    this.searchTerm$
      .pipe(
        map((term) => term.trim().toLowerCase()),
        distinctUntilChanged(),
        debounceTime(300),
        takeUntil(this.destroy$)
      )
      .subscribe({
        next: (term) => {
          this.normalizedSearchTerm = term;
          this.applyFilters();
          this.cdr.markForCheck();
        }
      });

    // Load initial tasks
    this.loadTasks();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  loadTasks(): void {
    this.loading = true;
    this.error = '';

    this.taskService.getAllTasks()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (tasks) => {
          this.setTasks(tasks || []);
          this.applyFilters();
          this.loading = false;
        },
        error: (error) => {
          this.error = error.message || 'Failed to load tasks';
          this.setTasks([]);
          this.filteredTasks = [];
          this.loading = false;
        }
      });
  }

  applyFilters(): void {
    const hasSearchTerm = this.normalizedSearchTerm.length > 0;
    const filtered: Task[] = [];

    for (const task of this.tasks) {
      if (!this.matchesSelectedFilter(task)) {
        continue;
      }

      if (hasSearchTerm) {
        const searchable = this.searchIndex.get(task.id) || '';
        if (!searchable.includes(this.normalizedSearchTerm)) {
          continue;
        }
      }

      filtered.push(task);
    }

    this.filteredTasks = filtered;

    if (this.selectedTaskId) {
      const selectedExists = filtered.some((task) => task.id === this.selectedTaskId);
      if (!selectedExists) {
        this.selectedTaskId = null;
      }
    }
  }

  onFilterChange(): void {
    this.applyFilters();
    this.cdr.markForCheck();
  }

  onSearchChange(): void {
    this.searchTerm$.next(this.searchTerm);
  }

  private setTasks(tasks: Task[]): void {
    this.tasks = tasks;
    this.rebuildSearchIndex();
  }

  selectTask(taskId: string): void {
    this.selectedTaskId = taskId;
    this.cdr.markForCheck();
  }

  isTaskSelected(taskId: string): boolean {
    return this.selectedTaskId === taskId;
  }

  getSelectedTask(): Task | null {
    if (!this.selectedTaskId) {
      return null;
    }

    return this.tasks.find((task) => task.id === this.selectedTaskId) || null;
  }

  clearSelectedTask(): void {
    this.selectedTaskId = null;
    this.cdr.markForCheck();
  }

  private rebuildSearchIndex(): void {
    this.searchIndex.clear();

    for (const task of this.tasks) {
      const searchable = [
        task.title,
        task.description,
        task.category,
        (task.tags || []).join(' ')
      ]
        .filter(Boolean)
        .join(' ')
        .toLowerCase();

      this.searchIndex.set(task.id, searchable);
    }
  }

  private matchesSelectedFilter(task: Task): boolean {
    switch (this.selectedFilter) {
      case 'pending':
        return task.status === TaskStatus.PENDING;
      case 'inProgress':
        return task.status === TaskStatus.IN_PROGRESS;
      case 'completed':
        return task.status === TaskStatus.COMPLETED;
      case 'starred':
        return task.starred === true;
      case 'all':
      default:
        return true;
    }
  }

  onStatusChange(task: Task, newStatus: string): void {
    this.taskService.updateTaskStatus(task.id, newStatus as TaskStatus)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.cdr.markForCheck();
        },
        error: (error) => {
          this.error = error.message || 'Failed to update task status';
          this.cdr.markForCheck();
        }
      });
  }

  handleStatusChange(event: Event, task: Task): void {
    const selectElement = event.target as HTMLSelectElement;
    this.onStatusChange(task, selectElement.value);
  }

  toggleStarred(event: Event, task: Task): void {
    event.stopPropagation();
    this.taskService.toggleStarred(task.id)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.cdr.markForCheck();
        },
        error: (error) => {
          this.error = error.message || 'Failed to toggle starred';
          this.cdr.markForCheck();
        }
      });
  }

  editTask(task: Task): void {
    this.router.navigate(['/tasks', task.id, 'edit']);
  }

  confirmDelete(event: Event, task: Task): void {
    event.stopPropagation();
    this.deleteConfirmId = task.id;
    this.deleteConfirmTaskTitle = task.title;
    this.cdr.markForCheck();
  }

  cancelDelete(event: Event): void {
    event.stopPropagation();
    this.deleteConfirmId = null;
    this.deleteConfirmTaskTitle = '';
    this.deleteLoading = false;
    this.cdr.markForCheck();
  }

  deleteTask(event: Event): void {
    event.stopPropagation();
    if (!this.deleteConfirmId || this.deleteLoading) return;

    this.deleteLoading = true;

    this.taskService.deleteTask(this.deleteConfirmId)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          if (this.selectedTaskId === this.deleteConfirmId) {
            this.selectedTaskId = null;
          }
          this.deleteConfirmId = null;
          this.deleteConfirmTaskTitle = '';
          this.deleteLoading = false;
          this.loadTasks(); // Reload to ensure UI is in sync
          this.cdr.markForCheck();
        },
        error: (error) => {
          this.error = error.message || 'Failed to delete task';
          this.deleteConfirmId = null;
          this.deleteConfirmTaskTitle = '';
          this.deleteLoading = false;
          this.cdr.markForCheck();
        }
      });
  }

  getPriorityClass(priority: TaskPriority): string {
    switch (priority) {
      case TaskPriority.HIGH:
        return 'priority-high';
      case TaskPriority.MEDIUM:
        return 'priority-medium';
      case TaskPriority.LOW:
        return 'priority-low';
      default:
        return '';
    }
  }

  getStatusClass(status: TaskStatus): string {
    switch (status) {
      case TaskStatus.PENDING:
        return 'status-pending';
      case TaskStatus.IN_PROGRESS:
        return 'status-in-progress';
      case TaskStatus.COMPLETED:
        return 'status-completed';
      case TaskStatus.CANCELLED:
        return 'status-cancelled';
      default:
        return '';
    }
  }

  createNewTask(): void {
    this.router.navigate(['/tasks/create']);
  }
}
<app-navbar></app-navbar>

<div class="task-list-container">
  <div class="task-list-header">
    <h1>My Day</h1>
    <button class="btn btn-primary" (click)="createNewTask()">+ Add Task</button>
  </div>

  <!-- Error Message -->
  @if (error) {
    <div class="alert alert-error">
      <span class="alert-icon">⚠️</span>
      <span>{{ error }}</span>
    </div>
  }

  @if (!getSelectedTask()) {
    <!-- Search and Filter Bar -->
    <div class="task-controls">
      <div class="search-box">
        <input
          type="text"
          class="search-input"
          placeholder="Search tasks..."
          [(ngModel)]="searchTerm"
          (input)="onSearchChange()"
        />
        <span class="search-icon">🔍</span>
      </div>

      <div class="filter-buttons">
        <button
          class="filter-btn"
          [class.active]="selectedFilter === 'all'"
          (click)="selectedFilter = 'all'; onFilterChange()"
        >
          All
        </button>
        <button
          class="filter-btn"
          [class.active]="selectedFilter === 'pending'"
          (click)="selectedFilter = 'pending'; onFilterChange()"
        >
          Pending
        </button>
        <button
          class="filter-btn"
          [class.active]="selectedFilter === 'inProgress'"
          (click)="selectedFilter = 'inProgress'; onFilterChange()"
        >
          In Progress
        </button>
        <button
          class="filter-btn"
          [class.active]="selectedFilter === 'completed'"
          (click)="selectedFilter = 'completed'; onFilterChange()"
        >
          Completed
        </button>
        <button
          class="filter-btn"
          [class.active]="selectedFilter === 'starred'"
          (click)="selectedFilter = 'starred'; onFilterChange()"
        >
          ⭐ Starred
        </button>
      </div>
    </div>
  }

  <!-- Loading State -->
  @if (loading) {
    <div class="loading-container">
      <div class="spinner"></div>
      <p>Loading tasks...</p>
    </div>
  }

  <!-- Empty State -->
  @if (!loading && filteredTasks.length === 0) {
    <div class="empty-state">
      <p>No tasks yet</p>
      <p class="empty-state-hint">Add your first task to start planning your day</p>
    </div>
  }

  <!-- Tasks List -->
  @if (!loading && filteredTasks.length > 0 && !getSelectedTask()) {
    <div class="tasks-grid" role="listbox" aria-label="Tasks">
      @for (task of filteredTasks; track task.id) {
        <div
          class="task-card"
          [class.completed]="task.status === TaskStatus.COMPLETED"
          (click)="selectTask(task.id)"
          role="option"
          [attr.aria-selected]="isTaskSelected(task.id)"
        >
          <div class="task-card-header">
            <div class="task-title-section">
              <select
                [value]="task.status"
                (change)="handleStatusChange($event, task)"
                (click)="$event.stopPropagation()"
                class="status-select"
                [class]="getStatusClass(task.status)"
              >
                <option value="PENDING">Pending</option>
                <option value="IN_PROGRESS">In Progress</option>
                <option value="COMPLETED">Completed</option>
                <option value="CANCELLED">Cancelled</option>
              </select>
              <h3 class="task-title">{{ task.title }}</h3>
            </div>
            <div class="task-actions">
              <button
                class="action-btn star-btn"
                [class.starred]="task.starred"
                (click)="toggleStarred($event, task)"
                title="Toggle starred"
              >
                {{ task.starred ? '⭐' : '☆' }}
              </button>
              <button
                class="action-btn edit-btn"
                (click)="editTask(task)"
                title="Edit task"
              >
                <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                  <path d="M12 20h9" />
                  <path d="M16.5 3.5a2.1 2.1 0 0 1 3 3L7 19l-4 1 1-4Z" />
                </svg>
              </button>
              <button
                class="action-btn delete-btn"
                (click)="confirmDelete($event, task)"
                title="Delete task"
              >
                <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                  <path d="M3 6h18" />
                  <path d="M8 6V4h8v2" />
                  <path d="M19 6l-1 14H6L5 6" />
                  <path d="M10 10v6" />
                  <path d="M14 10v6" />
                </svg>
              </button>
            </div>
          </div>

          <p class="task-description">{{ task.description }}</p>

          <div class="task-meta">
            <div class="meta-item">
              <span class="meta-label">Priority:</span>
              <span [class]="'priority ' + getPriorityClass(task.priority)">
                {{ task.priority }}
              </span>
            </div>

            @if (task.dueDate) {
              <div class="meta-item">
                <span class="meta-label">Due:</span>
                <span>{{ task.dueDate | date: 'MMM d, yyyy' }}</span>
              </div>
            }

            @if (task.category) {
              <div class="meta-item">
                <span class="meta-label">Category:</span>
                <span class="category-badge">{{ task.category }}</span>
              </div>
            }
          </div>

          @if (task.tags && task.tags.length > 0) {
            <div class="task-tags">
              @for (tag of task.tags; track tag) {
                <span class="tag">{{ tag }}</span>
              }
            </div>
          }
        </div>
      }
    </div>
  }

  @if (!loading && getSelectedTask(); as selectedTask) {
    <section class="task-details-view" aria-label="Selected task details">
      <div class="details-topbar">
        <button class="back-btn" (click)="clearSelectedTask()">← Back to Tasks</button>
      </div>

      <div class="details-card">
        <div class="details-header">
          <h2>Task Details</h2>
        </div>

        <div class="details-main">
          <p class="details-title">{{ selectedTask.title }}</p>
          <p class="details-description">{{ selectedTask.description }}</p>

          <div class="details-meta-grid">
            <div class="detail-chip">
              <span class="label">Status</span>
              <span class="value">{{ selectedTask.status }}</span>
            </div>
            <div class="detail-chip">
              <span class="label">Priority</span>
              <span class="value">{{ selectedTask.priority }}</span>
            </div>
            <div class="detail-chip">
              <span class="label">Created</span>
              <span class="value">{{ selectedTask.createdAt | date: 'MMM d, y, h:mm a' }}</span>
            </div>
            <div class="detail-chip">
              <span class="label">Updated</span>
              <span class="value">{{ selectedTask.updatedAt | date: 'MMM d, y, h:mm a' }}</span>
            </div>
            @if (selectedTask.dueDate) {
              <div class="detail-chip">
                <span class="label">Due Date</span>
                <span class="value">{{ selectedTask.dueDate | date: 'MMM d, y' }}</span>
              </div>
            }
            @if (selectedTask.category) {
              <div class="detail-chip">
                <span class="label">Category</span>
                <span class="value">{{ selectedTask.category }}</span>
              </div>
            }
          </div>

          @if (selectedTask.tags && selectedTask.tags.length > 0) {
            <div class="details-tags">
              <p>Tags</p>
              <div>
                @for (tag of selectedTask.tags; track tag) {
                  <span>{{ tag }}</span>
                }
              </div>
            </div>
          }
        </div>

        <div class="details-actions">
          <button class="btn btn-secondary" (click)="clearSelectedTask()">Back</button>
          <button class="btn btn-danger" (click)="confirmDelete($event, selectedTask)">Delete</button>
          <button class="btn btn-primary" (click)="editTask(selectedTask)">Edit Task</button>
        </div>
      </div>
    </section>
  }

  @if (deleteConfirmId) {
    <div class="delete-modal-backdrop" (click)="cancelDelete($event)">
      <div class="delete-modal" (click)="$event.stopPropagation()" role="dialog" aria-modal="true" aria-labelledby="delete-title">
        <div class="delete-modal-icon" aria-hidden="true">
          <svg viewBox="0 0 24 24" focusable="false">
            <path d="M3 6h18" />
            <path d="M8 6V4h8v2" />
            <path d="M19 6l-1 14H6L5 6" />
            <path d="M10 10v6" />
            <path d="M14 10v6" />
          </svg>
        </div>
        <h3 id="delete-title">Delete task</h3>
        <p>
          Are you sure you want to delete
          <strong>{{ deleteConfirmTaskTitle }}</strong>?
          This action cannot be undone.
        </p>
        <div class="delete-modal-actions">
          <button class="btn btn-secondary" (click)="cancelDelete($event)" [disabled]="deleteLoading">Cancel</button>
          <button class="btn btn-danger" (click)="deleteTask($event)" [disabled]="deleteLoading">
            @if (!deleteLoading) {
              <span>Delete Task</span>
            } @else {
              <span>Deleting...</span>
            }
          </button>
        </div>
      </div>
    </div>
  }
</div>
